class Solution:
    def searchMatrix(self, matrix: list[list[int]], target: int) -> bool:
        if not matrix or not matrix[0]:
            return False

        rows = len(matrix)
        cols = len(matrix[0])

        # Start from the top-right corner of the matrix
        row = 0
        col = cols - 1

        while row < rows and col >= 0:
            current_val = matrix[row][col]
            if current_val == target:
                return True
            elif current_val < target:
                # If current value is less than target, target must be below
                # (since current row is sorted left to right, so elements to the left are smaller;
                # current column is sorted top to bottom, so elements above are smaller).
                row += 1
            else: # current_val > target
                # If current value is greater than target, target must be to the left
                # (since current row is sorted left to right, so elements to the right are larger;
                # current column is sorted top to bottom, so elements below are larger).
                col -= 1

        return False
